package me.tr.trformatter.strings;public class IndexedCString extends CString {    private final int start;    private final int end;    public IndexedCString(String value, int start, int end) {        super(value);        this.start = start;        this.end = end;    }    public IndexedCString(char[] value, int start, int end) {        super(value);        this.start = start;        this.end = end;    }    public IndexedCString(byte[] value, int start, int end) {        super(value);        this.start = start;        this.end = end;    }    public int getStart() {        return start;    }    public int getEnd() {        return end;    }}